THE CLAIM:
{
 "title": "A third of Year-1 hardware wins get returned, cutting realized share",
 "narrative": "The model assumes the venture keeps whatever small share it wins in Year 1. But in the reference class, 30% of deployed industrial hardware systems are never fully accepted and get pulled back out. That makes the Year-1 number roughly 30% too high, and the lost accounts also undercut the Year-2 benchmark that assumes they survive.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "30% of deployed industrial hardware systems were never fully accepted",
   "refs": [
    "digest:obtainable-benchmark#c12"
   ]
  },
  {
   "step": "propagation",
   "text": "First-year wins are pilots; PDU acceptance depends on post-install integration",
   "refs": [
    "profile:Stage",
    "ledger:cust.operator-mid",
    "digest:cr3-vendors#c4"
   ]
  },
  {
   "step": "model-impact",
   "text": "obtainableFactor is gross; net of returns, Year-1 share drops 30%",
   "refs": [
    "ledger:obtainableFactor",
    "digest:obtainable-benchmark#c0"
   ]
  }
 ],
 "falsifier": "The first three pilot deployments pass formal customer acceptance within 90 days of install, with no rollback in the following two quarters.",
 "category": "execution",
 "evidence": [
  {
   "title": "The Economics of POC",
   "sourceType": "industry-report",
   "publisher": "Deploy 95 (Trista Li)",
   "date": "2026-04-14",
   "excerpt": "Thirty percent of deployed systems were never fully accepted: customers would sign, we’d deploy, and six months later, it came back. We were sending teams to uninstall while trying to hit revenue targets.",
   "url": "https://deploy95.substack.com/p/the-economics-of-poc",
   "attached": true
  },
  {
   "title": "Cisco Survey Reveals Close to Three-Fourths of IoT Projects Are Failing",
   "sourceType": "industry-report",
   "publisher": "Cisco",
   "date": "2017-05-23",
   "excerpt": "60 percent of IoT initiatives stall at the Proof of Concept (PoC) stage and only 26 percent of companies have had an IoT initiative that they considered a complete success. Even worse: a third of all completed projects were not considered a success.",
   "url": "https://newsroom.cisco.com/c/r/newsroom/en/us/a/y2017/m05/cisco-survey-reveals-close-to-three-fourths-of-iot-projects-are-failing.html",
   "attached": true
  },
  {
   "title": "Telefónica Germany upgrades data center operations with Vertiv PowerIT rPDUs",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": null,
   "excerpt": "Vertiv delivered Vertiv™ PowerIT switched rPDUs... deploying energy-efficient critical infrastructure solutions [under a] strong, multi-year partnership — illustrating that PDU acceptance in enterprise accounts leans heavily on an existing vendor track record.",
   "url": "https://www.vertiv.com/495b0e/globalassets/content---assets-2025/documents/vertiv-telefonica_marketing-thought-leadership-case-study_emea-english.pdf",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

